# Ordinary Least Squares
# Y = Xβ + ε

import numpy as np
import pandas as pd
from rpy2.robjects import pandas2ri
from rpy2.robjects.packages import importr
import rpy2.robjects as ro
from rpy2.robjects import pandas2ri
from rpy2.robjects.conversion import localconverter
import rpy2.robjects.numpy2ri
from sklearn.preprocessing import StandardScaler


# Функция для загрузки данных из Excel (первый столбец - регионы, остальные - годы)
def load_data(file_path):
    df = pd.read_excel(file_path)
    years = df.columns[1:].astype(int)  # Годы из заголовков столбцов
    data = df.iloc[:, 1:].values  # Данные (регионы x годы)
    regions = df.iloc[:, 0].values  # Названия регионов
    return data, years, regions


# Загрузка всех данных
y_data, years, regions = load_data(r'/Users/nastya/Documents/диплом/нир/ipc.xlsx')
x1_data, _, _ = load_data(r'/Users/nastya/Documents/диплом/нир/врп чистый(ндн).xlsx')
x2_data, _, _ = load_data(r'/Users/nastya/Documents/диплом/нир/прирост населения.xlsx')
x3_data, _, _ = load_data(r'/Users/nastya/Documents/диплом/нир/производство.xlsx')
x4_data, _, _ = load_data(r'/Users/nastya/Documents/диплом/нир/среднемесячная зарплата.xlsx')
x5_data, _, _ = load_data(r'/Users/nastya/Documents/диплом/нир/безработица.xlsx')

# Проверка размерностей данных
n_regions = len(regions)
n_years = len(years)
assert all(d.shape == (n_regions, n_years) for d in [y_data, x1_data, x2_data, x3_data, x4_data, x5_data])

# Создаем DataFrame с панельными данными
data = []
for i, year in enumerate(years):
    for j, region in enumerate(regions):
        row = {
            'id': j + 1,
            'region': region,  # название региона
            'time': year,
            'y': y_data[j, i],  # целевая переменная
            'x1': x1_data[j, i],  # ВРП чистый
            'x2': x2_data[j, i],  # прирост населения
            'x3': x3_data[j, i],  # производство
            'x4': x4_data[j, i],  # среднемесячная зарплата
            'x5': x5_data[j, i],  # безработица
        }
        data.append(row)

panel_data = pd.DataFrame(data)

# нормализация
cols = ['x1','x2','x3','x4','x5']

scaler = StandardScaler()
panel_data[cols] = scaler.fit_transform(panel_data[cols])


