def diagnose_weight_matrix(W):
    print("Диагностика матрицы весов:")
    print(f"Диагональные элементы: {np.diag(W)[:5]}... (должны быть нули)")
    row_sums = W.sum(axis=1)
    print(f"Минимальная сумма строк: {row_sums.min()}")
    print(f"Регионы с нулевой суммой: {np.where(row_sums == 0)[0]}")
    cond_number = np.linalg.cond(W)
    print(f"Число обусловленности матрицы: {cond_number:.2e}")

diagnose_weight_matrix(W)

